protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9: discriminator property renamed from "Discriminator" to "$type".
        // Preserve old name so existing documents and direct SQL queries still work.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9: id values no longer include the discriminator prefix.
        // Preserve "Product|123" format so existing 500K documents remain accessible.
        entity.HasRootDiscriminatorInJsonId(true);
    });

    // Removed: HasIndex() now throws for Cosmos DB entities.
    // Manage indexing via the container's indexing policy in Azure Portal / Bicep / Terraform.
}

